class Solution:
    def minXor(self, nums, k):
        n = len(nums)
        best = [float('inf')]
        def rec(start, pieces, cur_max):
            if cur_max >= best[0]:
                return
            if pieces == 1:
                x = 0
                for v in nums[start:]:
                    x ^= v
                best[0] = min(best[0], max(cur_max, x))
                return
            x = 0
            for end in range(start, n - pieces + 1):
                x ^= nums[end]
                rec(end + 1, pieces - 1, max(cur_max, x))
        rec(0, k, 0)
        return best[0]

