class Solution:
    def minXor(self, nums, k):
        n = len(nums)
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] ^ nums[i]
        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            top = min(i, k)
            for j in range(1, top + 1):
                best = INF
                for p in range(j - 1, i):
                    if dp[p][j - 1] == INF:
                        continue
                    seg = pre[i] ^ pre[p]
                    cand = dp[p][j - 1] if dp[p][j - 1] > seg else seg
                    if cand < best:
                        best = cand
                dp[i][j] = best
        return dp[n][k]

