var minXor = function(nums, k) {
    const n = nums.length;
    const pre = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) pre[i + 1] = pre[i] ^ nums[i];
    const INF = Infinity;
    const dp = Array.from({ length: n + 1 }, () => new Array(k + 1).fill(INF));
    dp[0][0] = 0;
    for (let i = 1; i <= n; i++) {
        const top = Math.min(i, k);
        for (let j = 1; j <= top; j++) {
            let best = INF;
            for (let p = j - 1; p < i; p++) {
                if (dp[p][j - 1] === INF) continue;
                const seg = pre[i] ^ pre[p];
                const cand = dp[p][j - 1] > seg ? dp[p][j - 1] : seg;
                if (cand < best) best = cand;
            }
            dp[i][j] = best;
        }
    }
    return dp[n][k];
};
